import React from 'react'
import { useSelector } from 'react-redux'

export const LevelPanel = () => {
  const state = useSelector(state => state)

  return (
    <fieldset>
      <legend>Level</legend>
      <table>
        <thead>
        <tr>
          <th>{`Level`}</th>
          <th>{`Kill Amount`}</th>
          <th>{`Level Upgrade Require`}</th>
        </tr>
        </thead>
        <tbody>
        <tr>
          <td>{state.player.level}</td>
          <td>{state.player.levelKillAmount}</td>
          <td>{state.player.levelKillAmountRequire}</td>
        </tr>
        </tbody>
      </table>
    </fieldset>
  )
}
